// // This module decrements its value on each rising edge of the clock signal when enabled. The counter can be asynchronously reset to zero when the reset signal is asserted. The current count value is output as a 4-bit signal.
module top_module(clk, rst, en, out);input clk, rst, en;
    output [3:0] out;

    reg [3:0] count;

    always @(posedge clk or posedge rst)
    begin
        if (rst)
            count <= 4'd0;
        else if (en)
            count <= count + 1;
    end

    assign out = count;
endmodule
